<template>
  <view class="page">
    <!-- 顶部欢迎区 -->
    <view class="header">
      <view class="title">欢迎使用AI备课</view>
      <view class="subtitle">全学段、全学科资源一键生成</view>
    </view>

    <!-- 核心功能卡片 (正方形) -->
    <view class="card-container">
      <view class="big-card" @click="handleAction('plan')">
        <view class="icon-emoji">📚</view>
        <view class="card-title">智能教案</view>
        <view class="card-desc">生成Word版标准教案</view>
      </view>
      <view class="big-card" @click="handleAction('quiz')">
        <view class="icon-emoji">✏️</view>
        <view class="card-title">达标测试</view>
        <view class="card-desc">100分制Word试卷</view>
      </view>
      <view class="big-card" @click="handleAction('html')">
        <view class="icon-emoji">🌐</view>
        <view class="card-title">互动课件</view>
        <view class="card-desc">精美H5演示网页</view>
      </view>
    </view>

    <!-- 福利Banner -->
    <view class="banner">
      <view class="banner-content">
        <view class="banner-icon">📢</view>
        <view class="banner-text">
          <view class="b-title">新用户福利</view>
          <view class="b-desc">注册即可享受第一天免费使用</view>
        </view>
        <button class="vip-btn" @click="goVip">立即开通VIP</button>
      </view>
    </view>
    
    <!-- 最近生成 -->
    <view class="section-title">最近生成</view>
    <view class="recent-list">
      <!-- 循环 historyList -->
      <view class="recent-item" v-for="(item, index) in historyList" :key="index">
        <view class="recent-tag">{{ item.subject }}</view>
        <view class="recent-info">
           <view class="recent-main">{{ item.topic }}</view>
           <view class="recent-time">{{ item.time }}</view>
           <!-- 增加下载按钮 -->
           <view class="action-btns">
             <text class="btn-text" @click="downloadFile(item.planUrl)">教案</text>
             <text class="btn-text" @click="downloadFile(item.quizUrl)">试卷</text>
             <text class="btn-text" @click="openH5(item.htmlUrl)">课件</text>
           </view>
        </view>
      </view>
      
      <!-- 如果没有记录时显示 -->
      <view v-if="historyList.length === 0" style="text-align: center; color: #ccc; padding: 20px;">
        暂无生成记录
      </view>
    </view>

	
    <!-- 自定义底部栏 -->
    <view class="footer-tabbar">
      <view class="tab-item active">首页</view>
      <view class="tab-item" @click="navTo('prepare')">备课</view>
      <view class="tab-item" @click="navTo('vip')">会员卡</view>
      <view class="tab-item" @click="navTo('mine')">我的</view>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue' 
import { onShow } from '@dcloudio/uni-app'

// 1. 初始化列表
const historyList = ref([])

// 2. 每次回到首页刷新列表
// index.vue 的 onShow 逻辑
onShow(() => {
  uni.request({
    url: 'http://127.0.0.1:8000/api/history',
    method: 'GET',
    success: (res) => {
      if (res.data.code === 200) {
        const baseUrl = 'http://127.0.0.1:8000/static/';
        
        // 适配你数据库里的 files_json 结构
        historyList.value = res.data.data.map(item => {
          // 注意：SQLAlchemy 返回的 JSON 字段通常直接就是对象
          const files = item.files_json; 
          return {
            topic: item.topic,
            subject: item.subject,
            time: item.created_at.replace('T', ' '),
            planUrl: baseUrl + files.plan,
            quizUrl: baseUrl + files.quiz,
            htmlUrl: baseUrl + files.html
          }
        });
      }
    }
  });
});

// 设置标题
uni.setNavigationBarTitle({ title: 'AI 备课' });

// --- 所有的跳转/下载函数 ---

// 修复：补全 openH5 函数（用于预览 HTML 课件）
const openH5 = (url) => {
  if (!url) return uni.showToast({ title: '链接不存在', icon: 'none' });
  // H5 环境下直接新窗口打开网页
  window.open(url);
};

// 修复：补全 downloadFile 函数（用于下载 Word 教案和试卷）
const downloadFile = (url) => {
  if (!url) return uni.showToast({ title: '链接不存在', icon: 'none' });
  // H5 环境下 window.open 也会触发浏览器下载 Word 文档
  window.open(url);
};

// 功能按钮跳转
const handleAction = (type) => {
  uni.setStorageSync('genType', type);
  uni.reLaunch({ url: '/pages/prepare/prepare' });
};

// 底部导航跳转
const navTo = (name) => {
  uni.reLaunch({ url: `/pages/${name}/${name}` });
};

// 跳转 VIP
const goVip = () => {
  uni.reLaunch({ url: '/pages/vip/vip' });
};
</script>

